#### 1.3 Event Bus

**File**: `src/workflows/event-bus.ts` (new)
**Changes**: Create the `WorkflowEventBus` interface and `InProcessEventBus` implementation

```typescript
import { EventEmitter } from "node:events";

export interface WorkflowEventBus {
  emit(event: string, data: unknown): void;
  on(event: string, handler: (data: unknown) => void): void;
  off(event: string, handler: (data: unknown) => void): void;
}

class InProcessEventBus implements WorkflowEventBus {
  private emitter = new EventEmitter();

  constructor() {
    this.emitter.setMaxListeners(100);
  }

  emit(event: string, data: unknown): void {
    this.emitter.emit(event, data);
  }

  on(event: string, handler: (data: unknown) => void): void {
    this.emitter.on(event, handler);
  }

  off(event: string, handler: (data: unknown) => void): void {
    this.emitter.off(event, handler);
  }
}

export const workflowEventBus: WorkflowEventBus = new InProcessEventBus();
```

