#### 2.4 DAG Engine

**File**: `src/workflows/engine.ts` (new)
**Changes**: Core engine with `startWorkflowExecution()`, `walkDag()`, `executeNode()`, graph helpers

```typescript
import type { Workflow, WorkflowNode, WorkflowDefinition, WorkflowRunStatus } from "../types";
import {
  createWorkflowRun,
  updateWorkflowRun,
  createWorkflowRunStep,
  updateWorkflowRunStep,
  getWorkflow,
  getWorkflowRun,
} from "../be/db";
import { executePropertyMatch, type PropertyMatchConfig } from "./nodes/property-match";
import { executeCreateTask, type CreateTaskConfig } from "./nodes/create-task";

export interface NodeResult {
  mode: "instant" | "async";
  nextPort: string;
  output: unknown;
}

export function findEntryNodes(def: WorkflowDefinition): WorkflowNode[] {
  const targets = new Set(def.edges.map((e) => e.target));
  return def.nodes.filter((n) => !targets.has(n.id));
}

export function getSuccessors(
  def: WorkflowDefinition,
  nodeId: string,
  port: string
): WorkflowNode[] {
  const edgesFromPort = def.edges.filter(
    (e) => e.source === nodeId && e.sourcePort === port
  );
  return edgesFromPort
    .map((e) => def.nodes.find((n) => n.id === e.target))
    .filter((n): n is WorkflowNode => n != null);
}

export async function startWorkflowExecution(
  workflow: Workflow,
  triggerData: unknown
): Promise<string> {
  const runId = crypto.randomUUID();
  createWorkflowRun({ id: runId, workflowId: workflow.id, triggerData });
  const ctx: Record<string, unknown> = { trigger: triggerData };
  const entryNodes = findEntryNodes(workflow.definition);
  await walkDag(workflow.definition, runId, ctx, entryNodes);
  return runId;
}

export async function walkDag(
  def: WorkflowDefinition,
  runId: string,
  ctx: Record<string, unknown>,
  startNodes: WorkflowNode[]
): Promise<void> {
  const visited = new Set<string>();
  const queue = [...startNodes];

  while (queue.length > 0) {
    const node = queue.shift()!;

    // Cycle guard: if we've already visited this node, stop traversal
    if (visited.has(node.id)) continue;
    visited.add(node.id);

    const stepId = crypto.randomUUID();
    createWorkflowRunStep({
      id: stepId,
      runId,
      nodeId: node.id,
      nodeType: node.type,
      input: ctx,
    });

    try {
      const result = await executeNode(node, ctx, runId, stepId);

      if (result.mode === "async") {
        // Async node: pause the run. Step stays as 'waiting'.
        updateWorkflowRunStep(stepId, { status: "waiting", output: result.output });
        updateWorkflowRun(runId, {
          status: "waiting",
          context: ctx as Record<string, unknown>,
        });
        return; // Execution stops — resumed by event bus
      }

      // Instant node: mark completed, add output to context, continue
      updateWorkflowRunStep(stepId, {
        status: "completed",
        output: result.output,
        finishedAt: new Date().toISOString(),
      });
      ctx[node.id] = result.output;

      const successors = getSuccessors(def, node.id, result.nextPort);
      queue.push(...successors);
    } catch (err) {
      updateWorkflowRunStep(stepId, {
        status: "failed",
        error: String(err),
        finishedAt: new Date().toISOString(),
      });
      updateWorkflowRun(runId, {
        status: "failed",
        error: String(err),
        finishedAt: new Date().toISOString(),
      });
      return;
    }
  }

  // No more nodes — workflow complete
  const run = getWorkflowRun(runId);
  if (run && run.status === "running") {
    updateWorkflowRun(runId, {
      status: "completed",
      context: ctx as Record<string, unknown>,
      finishedAt: new Date().toISOString(),
    });
  }
}

async function executeNode(
  node: WorkflowNode,
  ctx: Record<string, unknown>,
  runId: string,
  stepId: string
): Promise<NodeResult> {
  switch (node.type) {
    // Trigger nodes pass through — they match during subscription, not execution
    case "trigger-new-task":
    case "trigger-task-completed":
    case "trigger-webhook":
    case "trigger-email":
    case "trigger-slack-message":
    case "trigger-github-event":
      return { mode: "instant", nextPort: "default", output: ctx.trigger };

    case "property-match":
      return executePropertyMatch(node.config as PropertyMatchConfig, ctx);

    case "create-task":
      return executeCreateTask(node.config as CreateTaskConfig, ctx, runId, stepId);

    default:
      throw new Error(`Unknown node type: ${node.type}`);
  }
}
```

#### 2.5 Resume Listener

**File**: `src/workflows/resume.ts` (new)
**Changes**: Event bus listener for task completion/failure, resumes paused workflow runs

```typescript
import type { WorkflowEventBus } from "./event-bus";
import type { WorkflowDefinition } from "../types";
import {
  getWorkflowRun,
  getWorkflowRunStep,
  getWorkflow,
  updateWorkflowRun,
  updateWorkflowRunStep,
  getWorkflowRunStepsByRunId,
} from "../be/db";
import { walkDag, getSuccessors } from "./engine";

interface TaskEvent {
  taskId: string;
  output?: string;
  agentId?: string;
  workflowRunId?: string;
  workflowRunStepId?: string;
  failureReason?: string;
}

export function setupWorkflowResumeListener(eventBus: WorkflowEventBus): void {
  eventBus.on("task.completed", async (data: unknown) => {
    const event = data as TaskEvent;
    if (!event.workflowRunId || !event.workflowRunStepId) return;
    await resumeFromTaskCompletion(event);
  });

  eventBus.on("task.failed", async (data: unknown) => {
    const event = data as TaskEvent;
    if (!event.workflowRunId || !event.workflowRunStepId) return;
    markRunFailed(event, event.failureReason ?? "Task failed");
  });

  eventBus.on("task.cancelled", async (data: unknown) => {
    const event = data as TaskEvent;
    if (!event.workflowRunId || !event.workflowRunStepId) return;
    markRunFailed(event, "Task was cancelled");
  });
}

async function resumeFromTaskCompletion(event: TaskEvent): Promise<void> {
  const run = getWorkflowRun(event.workflowRunId!);
  if (!run || run.status !== "waiting") return;

  const step = getWorkflowRunStep(event.workflowRunStepId!);
  if (!step || step.status !== "waiting") return;

  const workflow = getWorkflow(run.workflowId);
  if (!workflow) return;

  // Mark step completed
  updateWorkflowRunStep(step.id, {
    status: "completed",
    output: { taskOutput: event.output },
    finishedAt: new Date().toISOString(),
  });

  // Resume context
  const ctx = (run.context ?? {}) as Record<string, unknown>;
  ctx[step.nodeId] = { taskOutput: event.output };
  updateWorkflowRun(run.id, { status: "running", context: ctx });

  // Continue DAG walk from successors
  const successors = getSuccessors(workflow.definition, step.nodeId, "default");
  await walkDag(workflow.definition, run.id, ctx, successors);
}

function markRunFailed(event: TaskEvent, reason: string): void {
  updateWorkflowRunStep(event.workflowRunStepId!, {
    status: "failed",
    error: reason,
    finishedAt: new Date().toISOString(),
  });
  updateWorkflowRun(event.workflowRunId!, {
    status: "failed",
    error: reason,
    finishedAt: new Date().toISOString(),
  });
}

export async function retryFailedRun(runId: string): Promise<void> {
  const run = getWorkflowRun(runId);
  if (!run || run.status !== "failed") throw new Error("Run is not in failed state");

  const workflow = getWorkflow(run.workflowId);
  if (!workflow) throw new Error("Workflow not found");

  // Find the failed step
  const steps = getWorkflowRunStepsByRunId(runId);
  const failedStep = steps.find((s) => s.status === "failed");
  if (!failedStep) throw new Error("No failed step found");

  // Reset step and run
  updateWorkflowRunStep(failedStep.id, { status: "pending", error: undefined });
  const ctx = (run.context ?? {}) as Record<string, unknown>;
  updateWorkflowRun(runId, { status: "running", error: undefined, context: ctx });

  // Resume from the failed node
  const node = workflow.definition.nodes.find((n) => n.id === failedStep.nodeId);
  if (!node) throw new Error(`Node ${failedStep.nodeId} not found in workflow definition`);
  await walkDag(workflow.definition, runId, ctx, [node]);
}
```

