// Extract phase headers and their status (checked/unchecked items)
const lines = FILE_CONTENT.split('\n');
let currentPhase = null;
let phases = [];
let inPhase = false;

for (const line of lines) {
  // Match phase headers like "## Phase 1: ..."
  const phaseMatch = line.match(/^##\s+Phase\s+(\d+):\s+(.+)/);
  if (phaseMatch) {
    currentPhase = { number: phaseMatch[1], title: phaseMatch[2], checked: 0, unchecked: 0, total: 0 };
    phases.push(currentPhase);
    inPhase = true;
    continue;
  }

  if (currentPhase && line.match(/^##\s/)) {
    inPhase = false;
    currentPhase = null;
  }

  if (currentPhase) {
    if (line.match(/^\s*-\s+\[x\]/i)) {
      currentPhase.checked++;
      currentPhase.total++;
    } else if (line.match(/^\s*-\s+\[\s\]/)) {
      currentPhase.unchecked++;
      currentPhase.total++;
    }
  }
}

console.log(`Total phases: ${phases.length}\n`);
for (const p of phases) {
  const status = p.checked === p.total && p.total > 0 ? '✅ DONE' : p.checked > 0 ? '🔄 PARTIAL' : '⬜ TODO';
  console.log(`Phase ${p.number}: ${p.title}`);
  console.log(`  Status: ${status} (${p.checked}/${p.total} items checked)\n`);
}
